/*
 * Fonte Lora (Medium 500, Bold 700) incorporada como Data URLs (base64) para a
 * exportacao autocontida do caderno.
 *
 * Derivado de:
 *   src/assets/fonts/Lora-Medium.ttf
 *   src/assets/fonts/Lora-Bold.ttf
 *
 * Licenca SIL Open Font License (src/assets/fonts/OFL.txt), por isso a Lora
 * pode ser redistribuida embutida no HTML exportado. Regenere este arquivo se
 * os arquivos .ttf de origem mudarem.
 */
export const loraFontFaceCss = "@font-face{font-family:\"Lora\";font-style:normal;font-weight:500;font-display:swap;src:url(\"data:font/ttf;base64,\") format(\"truetype\")}@font-face{font-family:\"Lora\";font-style:normal;font-weight:700;font-display:swap;src:url(\"data:font/ttf;base64,\") format(\"truetype\")}";
